function () {
  const backend = ScheduleFlow.allBackendAppointments().map(a => ScheduleFlow.normalizeAppointment(a));
  const local = ScheduleFlow.allLocalAppointments().map(a => ScheduleFlow.normalizeAppointment(a));
  const seen = new Set();
  return [...local, ...backend].filter(a => {
