actionConfiguration.body:
async function (row) {
  const dentists = ScheduleFlow.dentists();
  const source = row || ({});
  const original = ScheduleFlow.normalizeAppointment(source);
  const appointmentId = Number(source.appointmentId || source['appointmentId'] || source['Appointment #'] || appsmith.store.selectedAppointmentId || 0);
  if (!appointmentId) {
    showAlert('Cannot update appointment: missing appointment ID.', 'error');
    return false;
  }
  const patientDetail = appsmith.store.selectedPatientDetail || ({});
  const patientId = Number(source.patientId || source['Patient ID'] || original.patientId || appsmith.URL.queryParams.patientId || appsmith.store.selectedPatientId || patientDetail.patientId || 0);
  if (!patientId) {
    showAlert('Cannot update appointment: missing patient ID.', 'error');
    return false;
  }
  let dentistId = Number(source.dentistId || source['Dentist ID'] || original.dentistId || 0);
  const rawDentist = String(source.dentistName || source.Dentist || original.dentistName || '').trim();
  if (!dentistId && rawDentist) {
    const rawLower = rawDentist.toLowerCase();
    const match = dentists.find(d => {
      const full = `${d.firstName || ''} ${d.lastName || ''}`.trim();
      return [String(d.dentistId || ''), `dr. ${full}`.toLowerCase(), full.toLowerCase()].includes(rawLower);
    });
    dentistId = Number(match && match.dentistId || 0);
  }
  if (!dentistId) {
    showAlert('Cannot update appointment: dentist is missing or could not be matched.', 'error');
    return false;
  }
  const dentist = dentists.find(d => Number(d.dentistId) === dentistId) || ({});
  const apptDate = source.appointmentDate || source.Date || original.appointmentDate || moment().format('YYYY-MM-DD');
  const rawTime = String(source.appointmentTime || source.Time || original.appointmentTime || '09:00').trim();
  const apptTime = (/^\d{1,2}:\d{2}:\d{2}$/).test(rawTime) ? rawTime : (/^\d{1,2}:\d{2}$/).test(rawTime) ? rawTime + ':00' : (/^\d{1,2}$/).test(rawTime) ? rawTime.padStart(2, '0') + ':00:00' : '09:00:00';
  const duration = Number(source.duration || source.Duration || original.duration || 30);
  const updatedAppt = {
    appointmentId,
    patientId,
    patientName: original.patientName || `${patientDetail.firstName || ''} ${patientDetail.lastName || ''}`.trim(),
    dentistId,
    dentistName: dentist.firstName ? `Dr. ${dentist.firstName} ${dentist.lastName}` : rawDentist,
    appointmentDate: moment(apptDate).format('YYYY-MM-DD'),
    appointmentTime: apptTime,
    duration,
    status: source.status || source.Status || original.status || 'Scheduled',
    notes: source.notes || source.Notes || original.notes || ''
  };
  const toMinutes = timeStr => {
    const parts = String(timeStr || '00:00:00').split(':').map(x => Number(x || 0));
    return (parts[0] || 0) * 60 + (parts[1] || 0);
  };
  const newStart = toMinutes(updatedAppt.appointmentTime);
  const newEnd = newStart + Number(updatedAppt.duration || 30);
  const conflict = ScheduleFlow.mergedAppointments().find(a => {
    if (Number(a.appointmentId || 0) === appointmentId) return false;
    if (Number(a.dentistId || 0) !== Number(updatedAppt.dentistId || 0)) return false;
    if (moment(a.appointmentDate).format('YYYY-MM-DD') !== updatedAppt.appointmentDate) return false;
    if (String(a.status || '').toLowerCase() === 'cancelled') return false;
    const start = toMinutes(a.appointmentTime);
    const end = start + Number(a.duration || 30);
    return newStart < end && start < newEnd;
  });
  if (conflict) {
    showAlert(`Appointment conflict: ${updatedAppt.dentistName || 'This dentist'} already has an appointment on ${updatedAppt.appointmentDate} at ${String(conflict.appointmentTime || '').slice(0, 5)}.`, 'error');
    return false;
  }
  const extractError = err => {
    const responseBody = update_appointments.data;
    if (err && typeof err === 'object') {
      if (err.message) return String(err.message);
      if (err.error) return String(err.error);
      if (err.data && typeof err.data === 'string') return err.data;
      if (err.data && err.data.message) return String(err.data.message);
    }
    if (responseBody && typeof responseBody === 'object') {
      if (responseBody.message) return String(responseBody.message);
      if (responseBody.error) return String(responseBody.error);
    }
    const status = update_appointments.responseMeta && update_appointments.responseMeta.statusCode;
    return status ? `HTTP ${status}` : 'Unknown backend error';
  };
  try {
    await storeValue('pendingUpdateAppointmentPayload', updatedAppt);
    await update_appointments.run();
    await get_appointments.run();
    const refreshedRows = ScheduleFlow.allBackendAppointments().map(a => ScheduleFlow.normalizeAppointment(a));
    const refreshed = refreshedRows.find(a => Number(a.appointmentId || 0) === appointmentId) || updatedAppt;
    await storeValue('selectedAppointment', refreshed);
    await storeValue('selectedAppointmentId', appointmentId);
    await storeValue('selectedPatientId', patientId);
    showAlert('Appointment updated successfully.', 'success');
    return true;
  } catch (e) {
    showAlert(`Appointment was not updated in the backend: ${extractError(e)}`, 'error');
    return false;
  }
}

