async function (row) {
  const tableRow = typeof AppointmentTable !== 'undefined' && (AppointmentTable.triggeredRow || AppointmentTable.selectedRow || (AppointmentTable.selectedRows || [])[0]) || ({});
  const raw = row || tableRow || ({});
  const merged = ScheduleFlow.mergedAppointments();
  let appointmentId = Number(raw.appointmentId || raw['appointmentId'] || raw['Appointment #'] || raw.id || tableRow && (tableRow.appointmentId || tableRow['appointmentId'] || tableRow['Appointment #'] || tableRow.id) || appsmith.store.selectedAppointmentId || 0);
  if (!appointmentId && typeof AppointmentTable !== 'undefined') {
    const triggeredIndex = Number(AppointmentTable.triggeredRowIndex);
    const selectedIndex = Number(AppointmentTable.selectedRowIndex);
    const idx = Number.isInteger(triggeredIndex) && triggeredIndex >= 0 ? triggeredIndex : Number.isInteger(selectedIndex) && selectedIndex >= 0 ? selectedIndex : -1;
    if (idx >= 0 && merged[idx]) {
      appointmentId = Number(merged[idx].appointmentId || 0);
    }
  }
  if (!appointmentId) {
    showAlert('Missing appointment ID.', 'error');
    return false;
  }
  const key = String(appointmentId);
  const nextLocalAppointments = ScheduleFlow.allLocalAppointments().filter(x => Number(x.appointmentId || 0) !== appointmentId);
  await storeValue('localAppointments', nextLocalAppointments);
  const visitMap = {
    ...appsmith.store.localVisitRecords || ({})
  };
  delete visitMap[key];
  await storeValue('localVisitRecords', visitMap);
  const serviceMap = {
    ...appsmith.store.localVisitServices || ({})
  };
  delete serviceMap[key];
  await storeValue('localVisitServices', serviceMap);
  const billMap = {
    ...appsmith.store.localBills || ({})
  };
  delete billMap[key];
  await storeValue('localBills', billMap);
  const nextBillingRows = (Array.isArray(appsmith.store.localBillingRows) ? appsmith.store.localBillingRows : []).filter(x => Number(x.appointmentId || 0) !== appointmentId);
  await storeValue('localBillingRows', nextBillingRows);
  if (Number(appsmith.store.selectedAppointmentId || 0) === appointmentId) {
    await removeValue('selectedAppointment');
    await removeValue('selectedAppointmentId');
    await removeValue('currentVisitId');
    await storeValue('visitStarted', false);
  }
  try {
    await delete_appointments.run({
      appointmentId
    });
  } catch (e) {}
  try {
    await get_appointments.run();
  } catch (e) {}
  showAlert('Deleted appointment', 'success');
  return true;
}

