async function (row) {
  const dentists = ScheduleFlow.dentists();
  const patientDetail = appsmith.store.selectedPatientDetail || ({});
  const patientId = Number(row.patientId || row["Patient ID"] || appsmith.URL.queryParams.patientId || appsmith.store.selectedPatientId || patientDetail.patientId || 0);
  if (!patientId) {
    showAlert('Cannot create appointment: missing patient ID.', 'error');
    return false;
  }
  let dentistId = Number(row.dentistId || row["Dentist ID"] || 0);
  const rawDentist = String(row.dentistName || row.Dentist || '').trim();
  if (!dentistId && rawDentist) {
    const rawLower = rawDentist.toLowerCase();
    const match = dentists.find(d => {
      const full = `${d.firstName || ''} ${d.lastName || ''}`.trim();
      return [String(d.dentistId || ''), `dr. ${full}`.toLowerCase(), full.toLowerCase()].includes(rawLower);
    });
    dentistId = Number(match && match.dentistId || 0);
  }
  if (!dentistId) {
    showAlert('Cannot create appointment: dentist is missing or could not be matched.', 'error');
    return false;
  }
  const dentist = dentists.find(d => Number(d.dentistId) === dentistId) || ({});
  const apptDate = row.appointmentDate || row.Date || moment().format('YYYY-MM-DD');
  const rawTime = String(row.appointmentTime || row.Time || '09:00').trim();
  const apptTime = (/^\d{1,2}:\d{2}:\d{2}$/).test(rawTime) ? rawTime : (/^\d{1,2}:\d{2}$/).test(rawTime) ? rawTime + ':00' : '09:00:00';
  const duration = Number(row.duration || row.Duration || 30);
  const newAppt = {
    patientId,
    patientName: row.patientName || row.Patient || `${patientDetail.firstName || ''} ${patientDetail.lastName || ''}`.trim(),
    dentistId,
    dentistName: dentist.firstName ? `Dr. ${dentist.firstName} ${dentist.lastName}` : rawDentist,
    appointmentDate: moment(apptDate).format('YYYY-MM-DD'),
    appointmentTime: apptTime,
    duration,
    status: row.status || row.Status || 'Scheduled',
    notes: row.notes || row.Notes || ''
  };
  const toMinutes = timeStr => {
    const parts = String(timeStr || '00:00:00').split(':').map(x => Number(x || 0));
    return (parts[0] || 0) * 60 + (parts[1] || 0);
  };
  const newStart = toMinutes(newAppt.appointmentTime);
  const newEnd = newStart + Number(newAppt.duration || 30);
  const conflict = ScheduleFlow.mergedAppointments().find(a => {
    if (Number(a.dentistId || 0) !== Number(newAppt.dentistId || 0)) return false;
    if (moment(a.appointmentDate).format('YYYY-MM-DD') !== newAppt.appointmentDate) return false;
    if (String(a.status || '').toLowerCase() === 'cancelled') return false;
    const start = toMinutes(a.appointmentTime);
    const end = start + Number(a.duration || 30);
    return newStart < end && start < newEnd;
  });
  if (conflict) {
    showAlert(`Appointment conflict: ${newAppt.dentistName || 'This dentist'} already has an appointment on ${newAppt.appointmentDate} at ${String(conflict.appointmentTime || '').slice(0, 5)}.`, 'error');
    return false;
  }
  const extractError = err => {
    const responseBody = add_appointments.data;
    if (err && typeof err === 'object') {
      if (err.message) return String(err.message);
      if (err.error) return String(err.error);
      if (err.data && typeof err.data === 'string') return err.data;
      if (err.data && err.data.message) return String(err.data.message);
    }
    if (responseBody && typeof responseBody === 'object') {
      if (responseBody.message) return String(responseBody.message);
      if (responseBody.error) return String(responseBody.error);
    }
    const status = add_appointments.responseMeta && add_appointments.responseMeta.statusCode;
    return status ? `HTTP ${status}` : 'Unknown backend error';
  };
  try {
    await storeValue('pendingAppointmentPayload', {
      patientId: newAppt.patientId,
      dentistId: newAppt.dentistId,
      appointmentDate: newAppt.appointmentDate,
      appointmentTime: newAppt.appointmentTime,
      duration: newAppt.duration,
      status: newAppt.status,
      notes: newAppt.notes
    });
    await add_appointments.run();
    await removeValue('pendingAppointmentPayload');
    await get_appointments.run();
    const responseId = Number(add_appointments.data && (add_appointments.data.appointmentId || add_appointments.data.data && add_appointments.data.data.appointmentId) || 0);
    const refreshedRows = ScheduleFlow.allBackendAppointments().map(a => ScheduleFlow.normalizeAppointment(a));
    const refreshed = refreshedRows.find(a => responseId && Number(a.appointmentId || 0) === responseId) || refreshedRows.find(a => Number(a.patientId || 0) === Number(newAppt.patientId || 0) && Number(a.dentistId || 0) === Number(newAppt.dentistId || 0) && moment(a.appointmentDate).format('YYYY-MM-DD') === newAppt.appointmentDate && String(a.appointmentTime || '') === String(newAppt.appointmentTime || '')) || newAppt;
    await storeValue('selectedAppointment', refreshed);
    await storeValue('selectedAppointmentId', refreshed.appointmentId || null);
    await storeValue('selectedPatientId', patientId);
    showAlert('Appointment saved to backend successfully.', 'success');
    return true;
  } catch (e) {
    showAlert(`Appointment was not saved to the backend: ${extractError(e)}`, 'error');
    return false;
  }
}

