async function (useModal) {
  const selected = BillingFlow.normalizeBill(appsmith.store.selectedBilling || ({}));
  if (!Number(selected.billId || 0) && !Number(selected.appointmentId || 0)) {
    showAlert('No billing row selected.', 'error');
    return false;
  }
  const amountPaid = Number((useModal ? inp_billing_amount_modal.text : inp_billing_amount.text) || 0);
  const paymentMethod = String((useModal ? inp_billing_method_modal.text : inp_billing_method.text) || '').trim();
  const paymentStatus = String((useModal ? inp_billing_status_modal.text : inp_billing_status.text) || 'Pending').trim() || 'Pending';
  const updated = BillingFlow.normalizeBill({
    ...selected,
    amountPaid,
    paymentMethod,
    paymentStatus,
    statusBadge: paymentStatus
  });
  await BillingFlow.upsertLocalBill(updated);
  try {
    await BillingFlow.persistBill(updated);
    await get_billing.run();
    showAlert('Billing updated', 'success');
  } catch (e) {
    showAlert('Billing updated locally for demo. Backend sync failed.', 'warning');
  }
  await removeValue('selectedBilling');
  return true;
}

