actionConfiguration.body:
async function (row) {
  const backendMax = BillingFlow.allBackendBills().reduce((m, x) => Math.max(m, Number(x.billId || 0)), 0);
  const localRows = BillingFlow.allLocalBills();
  const localMax = localRows.reduce((m, x) => Math.max(m, Number(x.billId || 0)), 0);
  const rawPatientName = String(row.patientName || row.Patient || '').trim();
  const patientId = Number(row.patientId || BillingFlow.patientIdFromName(rawPatientName) || appsmith.URL.queryParams.patientId || appsmith.store.selectedPatientId || 0);
  const patientName = rawPatientName || BillingFlow.patientNameFromId(patientId) || (patientId ? `Patient #${patientId}` : '');
  const totalAmount = Number(row.totalAmount || row.Total || 0);
  const amountPaid = Number(row.amountPaid || row.Paid || 0);
  const paymentMethod = String(row.paymentMethod || row.Method || '').trim();
  const paymentStatus = String(row.paymentStatus || row.Status || (totalAmount > 0 && amountPaid >= totalAmount ? 'Paid' : 'Pending')).trim() || 'Pending';
  const billingDate = row.billingDate || row.Date ? moment(row.billingDate || row.Date).format('YYYY-MM-DD') : moment().format('YYYY-MM-DD');
  const newBill = {
    billId: Math.max(backendMax, localMax, 0) + 1,
    patientId,
    appointmentId: Number(row.appointmentId || 0),
    patientName,
    totalAmount,
    amountPaid,
    paymentMethod,
    paymentStatus,
    billingDate,
    statusBadge: paymentStatus
  };
  await BillingFlow.upsertLocalBill(newBill);
  try {
    await BillingFlow.persistBill(newBill);
    await get_billing.run();
    showAlert('Added bill', 'success');
  } catch (e) {
    showAlert('Bill saved locally for demo. Backend add failed.', 'warning');
  }
  return true;
}

