actionConfiguration.body:
function (b) {
  const patientId = Number(b.patientId || 0);
  const patientName = b.patientName || (b.patient && b.patient.firstName ? `${b.patient.firstName} ${b.patient.lastName}` : '') || BillingFlow.patientNameFromId(patientId) || (patientId ? `Patient #${patientId}` : '');
  const totalAmount = Number(b.totalAmount || 0);
  const amountPaid = Number(b.amountPaid || 0);
  const billingDate = b.billingDate ? moment(b.billingDate).format('YYYY-MM-DD') : moment().format('YYYY-MM-DD');
  const balanceDue = Math.max(0, totalAmount - amountPaid);
  const isPaid = totalAmount > 0 && amountPaid >= totalAmount;
  const isOverdue = balanceDue > 0 && moment(billingDate, 'YYYY-MM-DD', true).isValid() && moment().startOf('day').isAfter(moment(billingDate, 'YYYY-MM-DD').add(30, 'days').endOf('day'));
  const paymentStatus = isPaid ? 'Paid' : isOverdue ? 'Overdue' : 'Pending';
  return {
    billId: Number(b.billId || 0),
    patientId,
    appointmentId: Number(b.appointmentId || 0),
    patientName,
    totalAmount,
    amountPaid,
    paymentMethod: b.paymentMethod || '',
    paymentStatus,
    billingDate,
    statusBadge: paymentStatus
  };
}

