async function (row) {
  const backendMax = InventoryFlow.allBackendItems().reduce((m, x) => Math.max(m, Number(x.itemId || 0)), 0);
  const localRows = InventoryFlow.allLocalItems();
  const localMax = localRows.reduce((m, x) => Math.max(m, Number(x.itemId || 0)), 0);
  const newItem = {
    itemId: Math.max(backendMax, localMax, 0) + 1,
    itemName: String(row.itemName || row.Item || '').trim(),
    category: String(row.category || row.Category || '').trim(),
    quantity: Number(row.quantity || row.Quantity || 0),
    unitPrice: Number(row.unitPrice || row['Unit Price'] || 0),
    reorderLevel: Number(row.reorderLevel || row['Reorder Level'] || 0),
    supplier: String(row.supplier || row.Supplier || '').trim(),
    lastRestocked: row.lastRestocked || row['Last Restocked'] ? moment(row.lastRestocked || row['Last Restocked']).format('YYYY-MM-DD') : moment().format('YYYY-MM-DD')
  };
  await storeValue('localInventoryRows', [newItem, ...localRows]);
  try {
    await add_inventory.run();
    await get_inventory.run();
    showAlert('Added inventory item', 'success');
  } catch (e) {
    showAlert('Inventory item saved locally for demo. Backend add failed.', 'warning');
  }
  return true;
}

