async function () {
  try {
    if (!get_patient_detail.data || get_patient_detail.data.error) {
      try {
        await get_patient_detail.run();
      } catch (e) {}
    }
    if (!get_patient_billing_detail.data || get_patient_billing_detail.data.error) {
      try {
        await get_patient_billing_detail.run();
      } catch (e) {}
    }
    if (!get_patient_dentists.data || get_patient_dentists.data.error) {
      try {
        await get_patient_dentists.run();
      } catch (e) {}
    }
    let appts = JSObject2.mergedAppointments();
    if (!appts.length) {
      const result = await get_patient_appointments_detail.run();
      appts = Array.isArray(result) ? result.map(a => JSObject2.normalizeAppointment(a)) : [];
    }
    const localVisits = appsmith.store.localVisitRecords || ({});
    const preferred = appts.find(a => localVisits[String(a.appointmentId)]) || appts.find(a => String(a.status || '').toLowerCase() === 'completed') || appts[0];
    if (preferred && preferred.appointmentId) {
      await storeValue('selectedAppointmentId', preferred.appointmentId);
      try {
        await get_patient_visit_detail.run();
      } catch (e) {}
    } else {
      await storeValue('selectedAppointmentId', null);
    }
    return true;
  } catch (e) {
    showAlert('Failed to load patient details', 'error');
    return false;
  }
}

