actionConfiguration.body:
function () {
  const patientId = JSObject2.currentPatientId();
  const normalize = b => ({
    billId: Number(b.billId || 0),
    appointmentId: Number(b.appointmentId || 0),
    patientId: Number(b.patientId || patientId || 0),
    billingDate: b.billingDate ? moment(b.billingDate).format('YYYY-MM-DD') : moment().format('YYYY-MM-DD'),
    totalAmount: Number(b.totalAmount || 0),
    amountPaid: Number(b.amountPaid || 0),
    paymentMethod: b.paymentMethod || '',
    paymentStatus: b.paymentStatus || 'Pending'
  });
  const local = (Array.isArray(appsmith.store.localBillingRows) ? appsmith.store.localBillingRows : []).filter(b => Number(b.patientId || 0) === patientId).map(normalize);
  const backend = (Array.isArray(get_patient_billing_detail.data) ? get_patient_billing_detail.data : []).filter(b => Number(b.patientId || patientId) === patientId).map(normalize);
  const seen = new Set();
  return [...local, ...backend].filter(b => {
    const key = Number(b.appointmentId || 0) > 0 ? `appt-${Number(b.appointmentId)}` : `bill-${Number(b.billId || 0)}`;
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  }).sort((a, b) => String(b.billingDate || '').localeCompare(String(a.billingDate || '')));
}

