  const localMap = appsmith.store.localVisitRecords || ({});
  const raw = get_patient_visit_detail.data;
  const backendVisits = Array.isArray(raw) ? raw.filter(v => v && !v.error) : raw && !raw.error ? [raw] : [];
  return appts.map(appt => {
    const visit = localMap[String(appt.appointmentId)] || backendVisits.find(v => Number(v.appointmentId || 0) === Number(appt.appointmentId)) || null;
    const dentistName = JSObject2.dentistNameFor(appt, visit);
    const completed = String(appt.status || '').toLowerCase() === 'completed';
    const fallbackComplaint = String(appt.notes || '').trim();
    return {
      appointmentId: Number(appt.appointmentId || 0),
      date: appt.appointmentDate || '',
      time: appt.appointmentTime || '',
      dentistName,
      chiefComplaint: visit?.chiefComplaint || (fallbackComplaint || (completed ? 'Completed visit' : '')),
      findings: visit?.findings || '',
      diagnosis: visit?.diagnosis || (completed ? 'Completed' : ''),
      treatmentPlan: visit?.treatmentPlan || '',
      hasMeaningfulData: !!visit || !!fallbackComplaint || completed
    };
  }).filter(x => x.hasMeaningfulData);
}

