actionConfiguration.body:
function () {
  const patientId = JSObject2.currentPatientId();
  const local = (Array.isArray(appsmith.store.localAppointments) ? appsmith.store.localAppointments : []).filter(a => Number(a.patientId || 0) === patientId).map(a => JSObject2.normalizeAppointment(a));
  const backend = (Array.isArray(get_patient_appointments_detail.data) ? get_patient_appointments_detail.data : []).filter(a => Number(a.patientId || patientId) === patientId).map(a => JSObject2.normalizeAppointment(a));
  const seen = new Set();
  return [...local, ...backend].filter(a => {
    const key = String(a.appointmentId || '');
    if (!key || seen.has(key)) return false;
    seen.add(key);
    return true;
  }).sort((a, b) => {
    const ad = `${a.appointmentDate || ''} ${a.appointmentTime || ''}`;
    const bd = `${b.appointmentDate || ''} ${b.appointmentTime || ''}`;
    return bd.localeCompare(ad);
  });
}

