actionConfiguration.body:
async function () {
  const a = VisitFlow.resolveAppointment();
  if (!a || !a.appointmentId) {
    showAlert('Missing appointment. Please open this page from Schedule.', 'error');
    return false;
  }
  const updated = {
    ...a,
    status: 'InProgress'
  };
  await storeValue('selectedAppointment', updated);
  const all = VisitFlow.allAppointments().map(x => Number(x.appointmentId) === Number(updated.appointmentId) ? {
    ...x,
    status: 'InProgress'
  } : x);
  await storeValue('localAppointments', all);
  const localVisits = {
    ...VisitFlow.localVisitMap()
  };
  localVisits[String(updated.appointmentId)] = {
    ...localVisits[String(updated.appointmentId)] || ({}),
    appointmentId: updated.appointmentId,
    started: true
  };
  await storeValue('localVisitRecords', localVisits);
  await storeValue('visitStarted', true);
  try {
    await update_visit_appointment_status.run({
      appointmentId: updated.appointmentId,
      patientId: Number(updated.patientId || 0),
      dentistId: Number(updated.dentistId || 0),
      appointmentDate: updated.appointmentDate,
      appointmentTime: updated.appointmentTime,
      duration: Number(updated.duration || 30),
      status: 'InProgress',
      notes: updated.notes || ''
    });
  } catch (e) {}
  showAlert('Visit started. Fill in the visit record below.', 'info');
  return true;
}

