        await get_visit_appointment_by_id.run({
          appointmentId: a.appointmentId
        });
      } catch (e) {}
      try {
        await get_visit_record_existing.run({
          appointmentId: a.appointmentId
        });
      } catch (e) {}
    }
    const p = VisitFlow.resolvePatient();
    if (p && p.patientId) {
      await storeValue('selectedPatientDetail', p);
      try {
        await get_visit_patient_detail.run({
          patientId: p.patientId
        });
      } catch (e) {}
    }
    const localVisit = a && a.appointmentId ? VisitFlow.getLocalVisit(a.appointmentId) : null;
    if (localVisit && localVisit.visitId) {
      await storeValue('currentVisitId', localVisit.visitId);
      await storeValue('visitStarted', !!localVisit.started);
    } else {
      try {
        const existing = a && a.appointmentId ? await get_visit_record_existing.run({
          appointmentId: a.appointmentId
        }) : null;
        const existingId = existing && (existing.visitId || existing.id);
        if (existingId) {
          await storeValue('currentVisitId', existingId);
          await storeValue('visitStarted', true);
        } else {
          await removeValue('currentVisitId');
          await storeValue('visitStarted', false);
        }
      } catch (e) {
        await removeValue('currentVisitId');
        await storeValue('visitStarted', false);
      }
    }
    return true;
  } catch (e) {
    return false;
  }
}

