export default {
  allBackendAppointments() {
    return Array.isArray(get_appointments.data) ? get_appointments.data : [];
  },
  allLocalAppointments() {
    return Array.isArray(appsmith.store.localAppointments) ? appsmith.store.localAppointments : [];
  },
  dentists() {
    return Array.isArray(get_dentists.data) ? get_dentists.data : [];
  },
  normalizeAppointment(a) {
    const dentists = this.dentists();
    const dentist = dentists.find(d => Number(d.dentistId) === Number(a.dentistId)) || {};
    const patientDetail = appsmith.store.selectedPatientDetail || {};
    const patientName = a.patientName || (Number(a.patientId) === Number(patientDetail.patientId) ? `${patientDetail.firstName || ''} ${patientDetail.lastName || ''}`.trim() : '') || (a.patient && a.patient.firstName ? `${a.patient.firstName} ${a.patient.lastName}` : '');
    const dentistName = a.dentistName || (dentist.firstName ? `Dr. ${dentist.firstName} ${dentist.lastName}` : (a.dentist && a.dentist.firstName ? `Dr. ${a.dentist.firstName} ${a.dentist.lastName}` : ''));
    return {
      appointmentId: a.appointmentId,
      patientId: Number(a.patientId || 0),
      patientName,
      dentistId: Number(a.dentistId || 0),
      dentistName,
      appointmentDate: a.appointmentDate,
      appointmentTime: a.appointmentTime,
      duration: Number(a.duration || 30),
      status: a.status || 'Scheduled',
      notes: a.notes || ''
    };
  },
  mergedAppointments() {
    const backend = this.allBackendAppointments().map(a => this.normalizeAppointment(a));
    const local = this.allLocalAppointments().map(a => this.normalizeAppointment(a));
    const seen = new Set();
    return [...local, ...backend].filter(a => {
      const key = String(a.appointmentId);
      if (seen.has(key)) return false;
      seen.add(key);
      return true;
    });
  },
  async addAppointment(row) {
  const dentists = this.dentists();
  const patientDetail = appsmith.store.selectedPatientDetail || {};

  const patientId = Number(
    row.patientId ||
    row["Patient ID"] ||
    appsmith.URL.queryParams.patientId ||
    appsmith.store.selectedPatientId ||
    patientDetail.patientId ||
    0
  );

  if (!patientId) {
    showAlert('Cannot create appointment: missing patient ID.', 'error');
    return false;
  }

  let dentistId = Number(row.dentistId || row["Dentist ID"] || 0);
  const rawDentist = String(row.dentistName || row.Dentist || '').trim();

  if (!dentistId && rawDentist) {
    const rawLower = rawDentist.toLowerCase();
    const match = dentists.find(d => {
      const full = `${d.firstName || ''} ${d.lastName || ''}`.trim();
      return [
        String(d.dentistId || ''),
        `dr. ${full}`.toLowerCase(),
        full.toLowerCase()
      ].includes(rawLower);
    });
    dentistId = Number((match && match.dentistId) || 0);
  }

  if (!dentistId) {
    showAlert('Cannot create appointment: dentist is missing or could not be matched.', 'error');
    return false;
  }

  const dentist = dentists.find(d => Number(d.dentistId) === dentistId) || {};
  const apptDate = row.appointmentDate || row.Date || moment().format('YYYY-MM-DD');
  const rawTime = String(row.appointmentTime || row.Time || '09:00').trim();
  const apptTime =
    /^\d{1,2}:\d{2}:\d{2}$/.test(rawTime) ? rawTime :
    /^\d{1,2}:\d{2}$/.test(rawTime) ? rawTime + ':00' :
    '09:00:00';

  const duration = Number(row.duration || row.Duration || 30);

  const newAppt = {
    patientId,
    patientName:
      row.patientName ||
      row.Patient ||
      `${patientDetail.firstName || ''} ${patientDetail.lastName || ''}`.trim(),
    dentistId,
    dentistName: dentist.firstName ? `Dr. ${dentist.firstName} ${dentist.lastName}` : rawDentist,
    appointmentDate: moment(apptDate).format('YYYY-MM-DD'),
    appointmentTime: apptTime,
    duration,
    status: row.status || row.Status || 'Scheduled',
    notes: row.notes || row.Notes || ''
  };

  const toMinutes = (timeStr) => {
    const parts = String(timeStr || '00:00:00').split(':').map(x => Number(x || 0));
    return ((parts[0] || 0) * 60) + (parts[1] || 0);
  };

  const newStart = toMinutes(newAppt.appointmentTime);
  const newEnd = newStart + Number(newAppt.duration || 30);

  const conflict = this.mergedAppointments().find(a => {
    if (Number(a.dentistId || 0) !== Number(newAppt.dentistId || 0)) return false;
    if (moment(a.appointmentDate).format('YYYY-MM-DD') !== newAppt.appointmentDate) return false;
    if (String(a.status || '').toLowerCase() === 'cancelled') return false;

    const start = toMinutes(a.appointmentTime);
    const end = start + Number(a.duration || 30);
    return newStart < end && start < newEnd;
  });

  if (conflict) {
    showAlert(
      `Appointment conflict: ${newAppt.dentistName || 'This dentist'} already has an appointment on ${newAppt.appointmentDate} at ${String(conflict.appointmentTime || '').slice(0, 5)}.`,
      'error'
    );
    return false;
  }

  const extractError = (err) => {
    const responseBody = add_appointments.data;
    if (err && typeof err === 'object') {
      if (err.message) return String(err.message);
      if (err.error) return String(err.error);
      if (err.data && typeof err.data === 'string') return err.data;
      if (err.data && err.data.message) return String(err.data.message);
    }
    if (responseBody && typeof responseBody === 'object') {
      if (responseBody.message) return String(responseBody.message);
      if (responseBody.error) return String(responseBody.error);
    }
    const status = add_appointments.responseMeta && add_appointments.responseMeta.statusCode;
    return status ? `HTTP ${status}` : 'Unknown backend error';
  };

  try {
    await storeValue('pendingAppointmentPayload', {
      patientId: newAppt.patientId,
      dentistId: newAppt.dentistId,
      appointmentDate: newAppt.appointmentDate,
      appointmentTime: newAppt.appointmentTime,
      duration: newAppt.duration,
      status: newAppt.status,
      notes: newAppt.notes
    });
    await add_appointments.run();
    await removeValue('pendingAppointmentPayload');

    await get_appointments.run();

    const responseId = Number(
      (add_appointments.data &&
        (add_appointments.data.appointmentId ||
          (add_appointments.data.data && add_appointments.data.data.appointmentId))) || 0
    );

    const refreshedRows = this.allBackendAppointments().map(a => this.normalizeAppointment(a));
    const refreshed =
      refreshedRows.find(a => responseId && Number(a.appointmentId || 0) === responseId) ||
      refreshedRows.find(a =>
        Number(a.patientId || 0) === Number(newAppt.patientId || 0) &&
        Number(a.dentistId || 0) === Number(newAppt.dentistId || 0) &&
        moment(a.appointmentDate).format('YYYY-MM-DD') === newAppt.appointmentDate &&
        String(a.appointmentTime || '') === String(newAppt.appointmentTime || '')
      ) ||
      newAppt;

    await storeValue('selectedAppointment', refreshed);
    await storeValue('selectedAppointmentId', refreshed.appointmentId || null);
    await storeValue('selectedPatientId', patientId);

    showAlert('Appointment saved to backend successfully.', 'success');
    return true;
  } catch (e) {
    showAlert(`Appointment was not saved to the backend: ${extractError(e)}`, 'error');
    return false;
  }
}
  ,
async deleteAppointment(row) {
    const tableRow = (typeof AppointmentTable !== 'undefined' && (AppointmentTable.triggeredRow || AppointmentTable.selectedRow || ((AppointmentTable.selectedRows || [])[0]))) || {};
    const raw = row || tableRow || {};
    const merged = this.mergedAppointments();
    let appointmentId = Number(
      raw.appointmentId
      || raw['appointmentId']
      || raw['Appointment #']
      || raw.id
      || (tableRow && (tableRow.appointmentId || tableRow['appointmentId'] || tableRow['Appointment #'] || tableRow.id))
      || appsmith.store.selectedAppointmentId
      || 0
    );

    if (!appointmentId && typeof AppointmentTable !== 'undefined') {
      const triggeredIndex = Number(AppointmentTable.triggeredRowIndex);
      const selectedIndex = Number(AppointmentTable.selectedRowIndex);
      const idx = Number.isInteger(triggeredIndex) && triggeredIndex >= 0
        ? triggeredIndex
        : (Number.isInteger(selectedIndex) && selectedIndex >= 0 ? selectedIndex : -1);
      if (idx >= 0 && merged[idx]) {
        appointmentId = Number(merged[idx].appointmentId || 0);
      }
    }

    if (!appointmentId) {
      showAlert('Missing appointment ID.', 'error');
      return false;
    }

    const key = String(appointmentId);

    const nextLocalAppointments = this.allLocalAppointments().filter(x => Number(x.appointmentId || 0) !== appointmentId);
    await storeValue('localAppointments', nextLocalAppointments);

    const visitMap = { ...(appsmith.store.localVisitRecords || {}) };
    delete visitMap[key];
    await storeValue('localVisitRecords', visitMap);

    const serviceMap = { ...(appsmith.store.localVisitServices || {}) };
    delete serviceMap[key];
    await storeValue('localVisitServices', serviceMap);

    const billMap = { ...(appsmith.store.localBills || {}) };
    delete billMap[key];
    await storeValue('localBills', billMap);

    const nextBillingRows = (Array.isArray(appsmith.store.localBillingRows) ? appsmith.store.localBillingRows : [])
      .filter(x => Number(x.appointmentId || 0) !== appointmentId);
    await storeValue('localBillingRows', nextBillingRows);

    if (Number(appsmith.store.selectedAppointmentId || 0) === appointmentId) {
      await removeValue('selectedAppointment');
      await removeValue('selectedAppointmentId');
      await removeValue('currentVisitId');
      await storeValue('visitStarted', false);
    }

    try {
      await delete_appointments.run({ appointmentId });
    } catch (e) {
      // local delete should still work even if backend delete fails
    }

    try { await get_appointments.run(); } catch (e) {}
    showAlert('Deleted appointment', 'success');
    return true;
  },


  async startEdit(row) {
    const appt = this.normalizeAppointment(row || {});
    if (!appt.appointmentId) {
      showAlert('Missing appointment.', 'error');
      return false;
    }
    await storeValue('editAppointment', appt);
    await storeValue('selectedAppointment', appt);
    await storeValue('selectedAppointmentId', appt.appointmentId);
    await storeValue('selectedPatientId', appt.patientId);
    return true;
  },

  async cancelEdit() {
    await removeValue('editAppointment');
    await removeValue('pendingUpdateAppointmentPayload');
    return true;
  },

  async submitEdit() {
    const current = appsmith.store.editAppointment || {};
    const row = {
      appointmentId: Number(current.appointmentId || 0),
      patientId: Number(EditPatientIdInput.text || current.patientId || 0),
      dentistId: Number(EditDentistIdInput.text || current.dentistId || 0),
      appointmentDate: EditDateInput.text || current.appointmentDate,
      appointmentTime: EditTimeInput.text || current.appointmentTime,
      duration: Number(EditDurationInput.text || current.duration || 30),
      status: EditStatusInput.text || current.status || 'Scheduled',
      notes: EditNotesInput.text || current.notes || ''
    };
    const ok = await this.updateAppointment(row);
    if (ok) {
      await removeValue('editAppointment');
      await removeValue('pendingUpdateAppointmentPayload');
    }
    return ok;
  },

async updateAppointment(row) {
    const dentists = this.dentists();
    const source = row || {};
    const original = this.normalizeAppointment(source);
    const appointmentId = Number(
      source.appointmentId ||
      source['appointmentId'] ||
      source['Appointment #'] ||
      appsmith.store.selectedAppointmentId ||
      0
    );

    if (!appointmentId) {
      showAlert('Cannot update appointment: missing appointment ID.', 'error');
      return false;
    }

    const patientDetail = appsmith.store.selectedPatientDetail || {};
    const patientId = Number(
      source.patientId ||
      source['Patient ID'] ||
      original.patientId ||
      appsmith.URL.queryParams.patientId ||
      appsmith.store.selectedPatientId ||
      patientDetail.patientId ||
      0
    );

    if (!patientId) {
      showAlert('Cannot update appointment: missing patient ID.', 'error');
      return false;
    }

    let dentistId = Number(source.dentistId || source['Dentist ID'] || original.dentistId || 0);
    const rawDentist = String(source.dentistName || source.Dentist || original.dentistName || '').trim();
