export default {
  allBackendAppointments() {
    return Array.isArray(get_appointments.data) ? get_appointments.data : [];
  },
  allLocalAppointments() {
    return Array.isArray(appsmith.store.localAppointments) ? appsmith.store.localAppointments : [];
  },
  dentists() {
    return Array.isArray(get_dentists.data) ? get_dentists.data : [];
  },
  normalizeAppointment(a) {
    const dentists = this.dentists();
    const dentist = dentists.find(d => Number(d.dentistId) === Number(a.dentistId)) || {};
    const patientDetail = appsmith.store.selectedPatientDetail || {};
    const patientName = a.patientName || (Number(a.patientId) === Number(patientDetail.patientId) ? `${patientDetail.firstName || ''} ${patientDetail.lastName || ''}`.trim() : '') || (a.patient && a.patient.firstName ? `${a.patient.firstName} ${a.patient.lastName}` : '');
    const dentistName = a.dentistName || (dentist.firstName ? `Dr. ${dentist.firstName} ${dentist.lastName}` : (a.dentist && a.dentist.firstName ? `Dr. ${a.dentist.firstName} ${a.dentist.lastName}` : ''));
    return {
      appointmentId: a.appointmentId,
      patientId: Number(a.patientId || 0),
      patientName,
      dentistId: Number(a.dentistId || 0),
      dentistName,
      appointmentDate: a.appointmentDate,
      appointmentTime: a.appointmentTime,
      duration: Number(a.duration || 30),
      status: a.status || 'Scheduled',
      notes: a.notes || ''
    };
  },
  mergedAppointments() {
    const backend = this.allBackendAppointments().map(a => this.normalizeAppointment(a));
    const local = this.allLocalAppointments().map(a => this.normalizeAppointment(a));
    const seen = new Set();
    return [...local, ...backend].filter(a => {
      const key = String(a.appointmentId);
      if (seen.has(key)) return false;
      seen.add(key);
      return true;
    });
  },
  async addAppointment(row) {
  const dentists = this.dentists();
  const patientDetail = appsmith.store.selectedPatientDetail || {};

  const patientId = Number(
    row.patientId ||
    row["Patient ID"] ||
    appsmith.URL.queryParams.patientId ||
    appsmith.store.selectedPatientId ||
    patientDetail.patientId ||
    0
  );

  if (!patientId) {
    showAlert('Cannot create appointment: missing patient ID.', 'error');
    return false;
  }

  let dentistId = Number(row.dentistId || row["Dentist ID"] || 0);
  const rawDentist = String(row.dentistName || row.Dentist || '').trim();

  if (!dentistId && rawDentist) {
    const rawLower = rawDentist.toLowerCase();
    const match = dentists.find(d => {
      const full = `${d.firstName || ''} ${d.lastName || ''}`.trim();
      return [
        String(d.dentistId || ''),
        `dr. ${full}`.toLowerCase(),
        full.toLowerCase()
      ].includes(rawLower);
    });
    dentistId = Number((match && match.dentistId) || 0);
  }

  if (!dentistId) {
    showAlert('Cannot create appointment: dentist is missing or could not be matched.', 'error');
    return false;
  }

  const dentist = dentists.find(d => Number(d.dentistId) === dentistId) || {};
  const apptDate = row.appointmentDate || row.Date || moment().format('YYYY-MM-DD');
  const rawTime = String(row.appointmentTime || row.Time || '09:00').trim();
  const apptTime =
    /^\d{1,2}:\d{2}:\d{2}$/.test(rawTime) ? rawTime :
    /^\d{1,2}:\d{2}$/.test(rawTime) ? rawTime + ':00' :
    '09:00:00';

  const duration = Number(row.duration || row.Duration || 30);

  const newAppt = {
    patientId,
    patientName:
      row.patientName ||
      row.Patient ||
      `${patientDetail.firstName || ''} ${patientDetail.lastName || ''}`.trim(),
    dentistId,
