export default {
  patients() {
    const selected = appsmith.store.selectedPatientDetail ? [appsmith.store.selectedPatientDetail] : [];
    const backend = Array.isArray(get_patients_billing.data) ? get_patients_billing.data : [];
    const merged = [...selected, ...backend];
    const seen = new Set();
    return merged.filter(p => {
      const key = String(p.patientId || '');
      if (!key || seen.has(key)) return false;
      seen.add(key);
      return true;
    });
  },
  allBackendBills() {
    return Array.isArray(get_billing.data) ? get_billing.data : [];
  },
  allLocalBills() {
    return Array.isArray(appsmith.store.localBillingRows) ? appsmith.store.localBillingRows : [];
  },
  patientNameFromId(patientId) {
    const selected = appsmith.store.selectedPatientDetail || {};
    if (Number(selected.patientId || 0) === Number(patientId)) {
      return `${selected.firstName || ''} ${selected.lastName || ''}`.trim();
    }
    const p = this.patients().find(x => Number(x.patientId) === Number(patientId)) || {};
    return p.firstName ? `${p.firstName} ${p.lastName}` : '';
  },
  patientIdFromName(name) {
    const raw = String(name || '').trim();
    if (!raw) return 0;
    const p = this.patients().find(x => [`${x.firstName} ${x.lastName}`, `${x.firstName||''} ${x.lastName||''}`.trim()].includes(raw)) || {};
