export default {
  currentPatientId() {
    return Number(appsmith.URL.queryParams.patientId || appsmith.store.selectedPatientId || ((appsmith.store.selectedPatientDetail || {}).patientId) || 0);
  },
  patient() {
    const id = this.currentPatientId();
    const selected = appsmith.store.selectedPatientDetail || {};
    if (id && Number(selected.patientId || 0) === id) return selected;
    const detail = get_patient_detail.data || {};
    if (id && Number(detail.patientId || 0) === id) return detail;
    return (detail && !detail.error && Object.keys(detail).length) ? detail : selected;
  },
  normalizeAppointment(a) {
    return {
      appointmentId: Number(a.appointmentId || 0),
      patientId: Number(a.patientId || this.currentPatientId() || 0),
      appointmentDate: a.appointmentDate || a.date || '',
      appointmentTime: a.appointmentTime || a.time || '',
      dentistId: Number(a.dentistId || 0),
      dentistName: a.dentistName || (a.dentist && a.dentist.firstName ? `Dr. ${a.dentist.firstName} ${a.dentist.lastName}` : (a.dentistId ? `Dentist #${a.dentistId}` : '—')),
      duration: Number(a.duration || 30),
      status: a.status || 'Scheduled',
      notes: a.notes || ''
    };
  },
  mergedAppointments() {
    const patientId = this.currentPatientId();
    const local = (Array.isArray(appsmith.store.localAppointments) ? appsmith.store.localAppointments : [])
      .filter(a => Number(a.patientId || 0) === patientId)
      .map(a => this.normalizeAppointment(a));
    const backend = (Array.isArray(get_patient_appointments_detail.data) ? get_patient_appointments_detail.data : [])
      .filter(a => Number(a.patientId || patientId) === patientId)
      .map(a => this.normalizeAppointment(a));
    const seen = new Set();
    return [...local, ...backend]
      .filter(a => {
        const key = String(a.appointmentId || '');
        if (!key || seen.has(key)) return false;
        seen.add(key);
        return true;
      })
      .sort((a, b) => {
        const ad = `${a.appointmentDate || ''} ${a.appointmentTime || ''}`;
        const bd = `${b.appointmentDate || ''} ${b.appointmentTime || ''}`;
        return bd.localeCompare(ad);
      });
  },
  mergedBills() {
    const patientId = this.currentPatientId();
    const normalize = (b) => ({
      billId: Number(b.billId || 0),
      appointmentId: Number(b.appointmentId || 0),
      patientId: Number(b.patientId || patientId || 0),
      billingDate: b.billingDate ? moment(b.billingDate).format('YYYY-MM-DD') : moment().format('YYYY-MM-DD'),
      totalAmount: Number(b.totalAmount || 0),
      amountPaid: Number(b.amountPaid || 0),
      paymentMethod: b.paymentMethod || '',
      paymentStatus: b.paymentStatus || 'Pending'
    });
    const local = (Array.isArray(appsmith.store.localBillingRows) ? appsmith.store.localBillingRows : [])
      .filter(b => Number(b.patientId || 0) === patientId)
      .map(normalize);
    const backend = (Array.isArray(get_patient_billing_detail.data) ? get_patient_billing_detail.data : [])
      .filter(b => Number(b.patientId || patientId) === patientId)
      .map(normalize);
    const seen = new Set();
    return [...local, ...backend]
      .filter(b => {
        const key = Number(b.appointmentId || 0) > 0 ? `appt-${Number(b.appointmentId)}` : `bill-${Number(b.billId || 0)}`;
        if (seen.has(key)) return false;
        seen.add(key);
        return true;
      })
      .sort((a, b) => String(b.billingDate || '').localeCompare(String(a.billingDate || '')));
  },
  selectedAppointment() {
    const selectedRow = tbl_patient_appointments.selectedRow || {};
