    await storeValue('localAppointments', all);
    await storeValue('selectedAppointment', { ...a, status: 'Completed' });

    const patient = this.resolvePatient();
    const patientName = `${patient.firstName || ''} ${patient.lastName || ''}`.trim()
      || a.patientName
      || (Number(a.patientId || 0) ? `Patient #${Number(a.patientId)}` : '');

    const existingRows = Array.isArray(appsmith.store.localBillingRows) ? appsmith.store.localBillingRows : [];
