export default {
  allAppointments() {
    const local = Array.isArray(appsmith.store.localAppointments) ? appsmith.store.localAppointments : [];
    const backend = Array.isArray(get_visit_appointments_all.data) ? get_visit_appointments_all.data : [];
    const merged = [...local, ...backend];
    const seen = new Set();
    return merged.filter(a => {
      const key = String(a.appointmentId || '');
      if (!key || seen.has(key)) return false;
      seen.add(key);
      return true;
    });
  },
  allPatients() {
    const selected = appsmith.store.selectedPatientDetail ? [appsmith.store.selectedPatientDetail] : [];
    const backend = Array.isArray(get_visit_patients_all.data) ? get_visit_patients_all.data : [];
    const merged = [...selected, ...backend];
    const seen = new Set();
    return merged.filter(p => {
      const key = String(p.patientId || '');
      if (!key || seen.has(key)) return false;
      seen.add(key);
      return true;
    });
  },
  currentAppointmentId() {
    return Number(appsmith.URL.queryParams.appointmentId || appsmith.store.selectedAppointmentId || 0);
  },
  currentPatientId() {
    return Number(appsmith.URL.queryParams.patientId || appsmith.store.selectedPatientId || 0);
  },
  resolveAppointment() {
    const apptId = this.currentAppointmentId();
    const patientId = this.currentPatientId();
    const selected = appsmith.store.selectedAppointment || {};
    if (apptId && Number(selected.appointmentId || 0) === apptId) return selected;
    const all = this.allAppointments();
    return all.find(a => Number(a.appointmentId || 0) === apptId) || all.find(a => Number(a.patientId || 0) === patientId) || {};
  },
  resolvePatient() {
    const patientId = Number((this.resolveAppointment().patientId) || this.currentPatientId() || 0);
    const selected = appsmith.store.selectedPatientDetail || {};
    if (patientId && Number(selected.patientId || 0) === patientId) return selected;
    if (get_visit_patient_detail.data && Number(get_visit_patient_detail.data.patientId || 0) === patientId) return get_visit_patient_detail.data;
    const all = this.allPatients();
    return all.find(p => Number(p.patientId || 0) === patientId) || {};
  },
  localVisitMap() {
    return appsmith.store.localVisitRecords || {};
  },
  localServiceMap() {
    return appsmith.store.localVisitServices || {};
  },
  localBillMap() {
    return appsmith.store.localBills || {};
  },
  getLocalVisit(appointmentId) {
    return this.localVisitMap()[String(appointmentId)] || null;
  },
  getServices(appointmentId) {
    const local = this.localServiceMap()[String(appointmentId)] || [];
    if (local.length) return local;
    return Array.isArray(get_visit_services_page.data) ? get_visit_services_page.data : [];
  },
  async initPage() {
    try {
      try { await get_visit_appointments_all.run(); } catch (e) {}
      try { await get_visit_patients_all.run(); } catch (e) {}
      try { await get_inventory_options.run(); } catch (e) {}
      const a = this.resolveAppointment();
      if (a && a.appointmentId) {
        await storeValue('selectedAppointment', a);
        await storeValue('selectedAppointmentId', a.appointmentId);
        await storeValue('selectedPatientId', a.patientId);
        try { await get_visit_appointment_by_id.run({ appointmentId: a.appointmentId }); } catch (e) {}
        try { await get_visit_record_existing.run({ appointmentId: a.appointmentId }); } catch (e) {}
      }
      const p = this.resolvePatient();
      if (p && p.patientId) {
        await storeValue('selectedPatientDetail', p);
        try { await get_visit_patient_detail.run({ patientId: p.patientId }); } catch (e) {}
      }
      const localVisit = a && a.appointmentId ? this.getLocalVisit(a.appointmentId) : null;
      if (localVisit && localVisit.visitId) {
        await storeValue('currentVisitId', localVisit.visitId);
        await storeValue('visitStarted', !!localVisit.started);
      } else {
        try {
          const existing = a && a.appointmentId ? await get_visit_record_existing.run({ appointmentId: a.appointmentId }) : null;
          const existingId = existing && (existing.visitId || existing.id);
          if (existingId) {
            await storeValue('currentVisitId', existingId);
            await storeValue('visitStarted', true);
          } else {
            await removeValue('currentVisitId');
            await storeValue('visitStarted', false);
          }
        } catch (e) {
          await removeValue('currentVisitId');
          await storeValue('visitStarted', false);
        }
      }
      return true;
    } catch (e) {
      return false;
    }
  },
  async startVisit() {
    const a = this.resolveAppointment();
    if (!a || !a.appointmentId) {
      showAlert('Missing appointment. Please open this page from Schedule.', 'error');
      return false;
    }
    const updated = { ...a, status: 'InProgress' };
    await storeValue('selectedAppointment', updated);
    const all = this.allAppointments().map(x => Number(x.appointmentId) === Number(updated.appointmentId) ? { ...x, status: 'InProgress' } : x);
    await storeValue('localAppointments', all);
    const localVisits = { ...this.localVisitMap() };
    localVisits[String(updated.appointmentId)] = { ...(localVisits[String(updated.appointmentId)] || {}), appointmentId: updated.appointmentId, started: true };
    await storeValue('localVisitRecords', localVisits);
    await storeValue('visitStarted', true);
    try {
      await update_visit_appointment_status.run({
        appointmentId: updated.appointmentId,
        patientId: Number(updated.patientId || 0),
        dentistId: Number(updated.dentistId || 0),
        appointmentDate: updated.appointmentDate,
        appointmentTime: updated.appointmentTime,
        duration: Number(updated.duration || 30),
        status: 'InProgress',
        notes: updated.notes || ''
      });
    } catch (e) {}
    showAlert('Visit started. Fill in the visit record below.', 'info');
    return true;
  },
  async saveVisitRecord() {
    const a = this.resolveAppointment();
    if (!a || !a.appointmentId) {
      showAlert('Missing appointment. Please open this page from Schedule.', 'error');
      return false;
    }
    if (!inp_chief_complaint.text || !inp_diagnosis.text) {
      showAlert('Please enter at least chief complaint and diagnosis.', 'error');
      return false;
    }
    const localVisits = { ...this.localVisitMap() };
    const localId = localVisits[String(a.appointmentId)]?.visitId || Number(`9${a.appointmentId}`);
    localVisits[String(a.appointmentId)] = {
      visitId: localId,
      appointmentId: a.appointmentId,
      chiefComplaint: inp_chief_complaint.text,
      findings: inp_findings.text,
      diagnosis: inp_diagnosis.text,
      treatmentPlan: inp_treatment_plan.text,
      started: true
    };
    await storeValue('localVisitRecords', localVisits);
    await storeValue('currentVisitId', localId);
    await storeValue('visitStarted', true);
    try {
      const existing = await get_visit_record_existing.run({ appointmentId: a.appointmentId });
      if (!(existing && (existing.visitId || existing.id))) {
        const result = await create_visit_record_page.run({ appointmentId: a.appointmentId });
        const visitId = result && (result.visitId || result.id);
        if (visitId) {
          localVisits[String(a.appointmentId)].visitId = visitId;
          await storeValue('localVisitRecords', localVisits);
          await storeValue('currentVisitId', visitId);
        }
      }
    } catch (e) {}
    showAlert('Visit record saved.', 'success');
    return true;
  },
  async addServiceToVisit() {
    const a = this.resolveAppointment();
    if (!a || !a.appointmentId) { showAlert('Missing appointment.', 'error'); return false; }
    const localVisit = this.getLocalVisit(a.appointmentId);
    if (!localVisit && !appsmith.store.currentVisitId) {
      showAlert('Save the visit record first.', 'error');
      return false;
    }
    if (!inp_service_name.text || !inp_service_unit_cost.text) {
      showAlert('Please enter service name and unit cost.', 'error');
      return false;
    }
    const serviceMap = { ...this.localServiceMap() };
    const existing = serviceMap[String(a.appointmentId)] || [];
    const itemId = Number(inp_inventory_item_id.text || 0) || null;
    const qty = Number(inp_service_qty.text || 1);
    const unitCost = Number(inp_service_unit_cost.text || 0);
    const newService = {
      serviceId: Date.now(),
      visitId: Number(appsmith.store.currentVisitId || localVisit?.visitId || 0),
      serviceName: inp_service_name.text,
      description: inp_service_desc.text,
      unitCost,
      quantity: qty,
      linkedInventoryItemId: itemId,
      subtotal: unitCost * qty
    };
    serviceMap[String(a.appointmentId)] = [...existing, newService];
    await storeValue('localVisitServices', serviceMap);
    try { await add_service_page.run(); } catch (e) {}
    resetWidget('inp_service_name', true);
    resetWidget('inp_service_desc', true);
    resetWidget('inp_service_unit_cost', true);
    resetWidget('inp_service_qty', true);
    resetWidget('inp_inventory_item_id', true);
    showAlert('Service added.', 'success');
    return true;
  },
  totalForAppointment() {
    const a = this.resolveAppointment();
    if (!a || !a.appointmentId) return 0;
    return this.getServices(a.appointmentId).reduce((sum, s) => sum + (Number(s.unitCost || 0) * Number(s.quantity || 0)), 0);
  },
  async completeVisitAndGenerateInvoice() {
    const a = this.resolveAppointment();
    if (!a || !a.appointmentId) {
      showAlert('Missing appointment. Please open this page from Schedule.', 'error');
      return false;
    }
    const localVisit = this.getLocalVisit(a.appointmentId);
    if (!localVisit && !appsmith.store.currentVisitId) {
      showAlert('Save the visit record first.', 'error');
      return false;
    }
    const total = this.totalForAppointment();
    const all = this.allAppointments().map(x => Number(x.appointmentId) === Number(a.appointmentId) ? { ...x, status: 'Completed' } : x);
    await storeValue('localAppointments', all);
    await storeValue('selectedAppointment', { ...a, status: 'Completed' });

    const patient = this.resolvePatient();
    const patientName = `${patient.firstName || ''} ${patient.lastName || ''}`.trim()
      || a.patientName
      || (Number(a.patientId || 0) ? `Patient #${Number(a.patientId)}` : '');

    const existingRows = Array.isArray(appsmith.store.localBillingRows) ? appsmith.store.localBillingRows : [];
    const existingBill = existingRows.find(x => Number(x.appointmentId || 0) === Number(a.appointmentId)) || {};
    const newBill = {
      billId: Number(existingBill.billId || `8${a.appointmentId}`),
      patientId: Number(a.patientId || 0),
      appointmentId: Number(a.appointmentId || 0),
      patientName,
      totalAmount: Number(total || 0),
      amountPaid: 0,
      paymentMethod: '',
      paymentStatus: Number(total || 0) > 0 ? 'Pending' : 'Paid',
      billingDate: moment().format('YYYY-MM-DD'),
      statusBadge: Number(total || 0) > 0 ? 'Pending' : 'Paid'
    };

    const nextBills = [newBill, ...existingRows.filter(x => Number(x.appointmentId || 0) !== Number(a.appointmentId || 0))];
    await storeValue('localBillingRows', nextBills);

    const bills = { ...this.localBillMap() };
    bills[String(a.appointmentId)] = newBill;
    await storeValue('localBills', bills);

    await storeValue('visitServiceTotal', total);

    try { await complete_visit_page.run({ appointmentId: a.appointmentId }); } catch (e) {}
    try {
      await create_billing_visit_page.run({
        billId: newBill.billId,
        patientId: newBill.patientId,
        appointmentId: newBill.appointmentId,
        totalAmount: newBill.totalAmount,
        amountPaid: newBill.amountPaid,
        paymentMethod: newBill.paymentMethod,
        paymentStatus: newBill.paymentStatus,
        billingDate: newBill.billingDate
      });
      try { await get_billing.run(); } catch (e) {}
    } catch (e) {}
    showAlert('Visit completed and invoice generated.', 'success');
    return navigateTo('Billing', { patientId: a.patientId, appointmentId: a.appointmentId }, 'SAME_WINDOW');
  }
}
